preToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
$logLevel = if ($env:VSTACK_HOOKS_LOG_LEVEL) { $env:VSTACK_HOOKS_LOG_LEVEL } else { 'minimal' }
$logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
$logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
New-Item -ItemType Directory -Force -Path $logDir | Out-Null
if ($logLevel -eq 'off') {
  exit 0
}
if ($logLevel -eq 'verbose') {
  Add-Content -Path (Join-Path $logDir 'hook-tool-use.log') -Value $inputText
  exit 0
}
$toolName = 'unknown'
try {
  $payload = $inputText | ConvertFrom-Json -ErrorAction Stop
  if ($payload.toolName) {
    $toolName = [string]$payload.toolName
  }
} catch {
}
$record = @{
  timestamp = (Get-Date).ToUniversalTime().ToString('o')
  event = 'preToolUse'
  tool_name = $toolName
  size_bytes = $inputText.Length
  estimated_tokens = [int][math]::Ceiling($inputText.Length / 4.0)
} | ConvertTo-Json -Compress
Add-Content -Path (Join-Path $logDir 'hook-tool-use.log') -Value $record

